    def load_BOM1(self):
        # 弹出文件选择框，只显示 Excel
        file_path, _ = QFileDialog.getOpenFileName(None,"选择BOM1文件","","Excel Files (*.xlsx *.xls)")
        if not file_path:
            return
        try:
            self.textBrowser.insertPlainText('加载BOM1\n')
            print('加载BOM1:')
            self.df1=pd.read_excel(file_path, sheet_name='材料清单', usecols=['Quantity', 'Reference'])
            self.textBrowser.insertPlainText('BOM1加载成功\n')
            self.textBrowser.insertPlainText(file_path + "\n")
            self.quantity_list1 = self.df1['Quantity']
            self.reference_list1 = self.df1['Reference'].tolist()
        except Exception as e:
            self.textBrowser.insertPlainText(f"BOM1 加载失败: {e}\n")

