    def demo_bom(self):
        # ====================== 下载 BOM 模版功能 ======================
        self.textBrowser.insertPlainText("\n📥 准备下载 BOM 模版文件...")

        # 在这里替换成你的真实模版下载链接
        demo_url = "https://raw.githubusercontent.com/mygithubma/BOM_Check/main/demo_bom.xlsx"

        save_path, _ = QFileDialog.getSaveFileName(None, "保存BOM模版", "BOM模版.xlsx", "Excel Files (*.xlsx)")
        if not save_path:
            self.textBrowser.insertPlainText("已取消下载\n")
            return

        self.DEMO.setEnabled(False)
        self.DEMO.setText("下载中...")

        self.download_thread = DownloadThread(demo_url, save_path)
        self.download_thread.progress.connect(lambda p: self.textBrowser.insertPlainText(f"下载进度：{p}%\r"))
        self.download_thread.finished.connect(self.demo_done)
        self.download_thread.error.connect(self.demo_error)
        self.download_thread.start()

    def demo_done(self, path):
        self.DEMO.setEnabled(True)
        self.DEMO.setText("BOM模版")
        self.textBrowser.append(f"\n✅ 下载完成！\n保存路径：{path}\n")
        # QMessageBox.information(None, "成功", "BOM模版下载完成！")

    def demo_error(self, msg):
        self.DEMO.setEnabled(True)
        self.DEMO.setText("BOM模版")
        self.textBrowser.append(f"\n❌ 下载失败：{msg}\n")
        # QMessageBox.critical(None, "失败", f"下载失败：{msg}")

